--UE et ses acquis
--IPAP
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IPAP',8,120,'PRINCIPES ALGORITHMIQUES ET PROGRAMMATION','752105U32D3',
cast('<ul class="prgm"><li>d''identifier différents langages de programmation existants ;</li><li>de mettre en oeuvre une méthodologie de résolution de problème (observation,résolution, expérimentation, validation) et de la justifier en fonction de l’objectif poursuivi ;</li><li>de concevoir, construire et représenter des algorithmes, en utilisant :</li><li class="l2">les types de données élémentaires,</li><li class="l2">les figures algorithmiques de base (séquence, alternative et répétitive),</li><li class="l2">les instructions,</li><li class="l2">les portées des variables,</li><li class="l2">les fonctions et procédures,</li><li class="l2">la récursivité,</li><li class="l2">les entrées/sorties,</li><li class="l2">les fichiers,</li><li class="l2">les structures de données de base (tableaux et enregistrements) ;</li><li>de traduire de manière adéquate des algorithmes en respectant les spécificités du langage utilisé (JAVA, PYTHON);</li><li>de documenter de manière complète et précise les programmes développés ;</li><li>de produire des tests pour valider les programmes développés.</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPAP',1,'mettre en oeuvre une représentation algorithmique du problème posé',30);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPAP',2,'de développer au moins un programme en respectant les spécificités du langage choisi',30);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPAP',3,'de mettre en oeuvre des procédures de test',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPAP',4,'de justifier la démarche mise en oeuvre dans l’élaboration du (ou des) programme(s)',20);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IPAP');

--IPID
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IPID',9,100,'PROJET D’INTEGRATION DE DEVELOPPEMENT','7534 35 U32 D2',
cast('<ul class="prgm"><li>de décrire, de caractériser et de produire le cahier des charges du projet;</li><li>d’identifier les acteurs (collaborateurs, prestataires de service, etc.) intervenant dans la réalisation d’un projet d’intégration d’une application, de caractériser leurs rôles, leurs droits et leurs responsabilités ;</li><li>de construire un dossier technique reprenant les différentes étapes;</li><li>de mettre en oeuvre le projet en développant, parmi les concepts suivants:</li><li class="l2">la gestion des contenus dynamiques au travers d’une interface administrateur sécurisé,</li><li class="l2">la pagination de l’affichage des résultats d’une requête,</li><li class="l2">l’intégration de services internes et tiers,</li><li class="l2">la gestion de sélections, de filtres et de recherches au sein de l’application,</li><li class="l2">la gestion de la sécurisation et des droits d’accès aux contenus (administrateur, utilisateur public, utilisateur enregistré, gestionnaire, etc.),</li><li class="l2">l’affichage différencié des contenus (accessibilité, langue, sécurité, fonctionnalités, disponibilité de l’information, etc.), en fonction des profils utilisateurs,</li><li class="l2">la programmation asynchrone (AJAX…),</li><li class="l2">l’optimisation du code, du cache et des échanges avec la base de données,</li><li class="l2">l’interaction avec un système de gestion de bases de données (récupérer, ajouter, modifier, supprimer des enregistrements, etc.) ;;</li><li class="l2">la programmation orientée objet,</li><li class="l2">l’exploitation d’un framework backend et d’un framework frontend (par exemple React Native),</li><li class="l2">etc.;</li><li>d’identifier des menaces et de sécuriser le site en exploitant par exemple :</li><li class="l2">l’utilisation des outils spécifiques de protection et d’identification,</li><li class="l2">la protection contre des injections SQL, des attaques XSS, des vols de session, par détournement de cookies, etc.,</li><li class="l2">la réécriture d’url,</li><li class="l2">les paramétrages et les restrictions d’accès au serveur,</li><li class="l2">etc. ;</li><li>de gérer des erreurs de programmation au moyen d’outils ou de techniques de débogage et d’y apporter une solution pertinente ;</li><li>d’utiliser à bon escient la documentation disponible.</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPID',1,'de produire et défendre un cahier des charges et son dossier technique par rapport à la proposition du chargé de cours',50);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPID',2,'d’implémenter une base de données et l’intégrité des données',30);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPID',3,'de déployer et de justifier le site répondant aux consignes figurant dans le cahier des charges',20);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IPID');

--IBD
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IIBD',5,60,'INITIATION AUX BASES DE DONNEES','2982 21 U31 D1',
CAST('<ul class="prgm"><li>de définir une base de données ;</li><li>de présenter les éléments essentiels d''un système de gestion de bases de données (SGBD) ;</li><li>de créer une table, un index en utilisant différents types de données et de formats d''affichage de ces données sur un système de gestion de bases de données relationnelles ;</li><li>d''expliciter les mécanismes relationnels et le schéma relationnel dans une base de données ;</li><li>d''implémenter sur des exemples pratiques le schéma relationnel ;</li><li>d''utiliser une clé primaire et les vues ;</li><li>d''introduire et d''utiliser des tables à jonctions (jointure) ;</li><li>d''utiliser les éléments essentiels d''un langage tel que SQL ;</li><li>de créer des tables à l''aide du langage choisi ;</li><li>d''effectuer des sélections à l''aide du langage de requête : requêtes, tri simple, tri multiple, élimination des doublons, requêtes avec création de champs, jointure, regroupement,… applications pratiques sur un système de gestion de bases de données relationnelles ;</li><li>d''appliquer les opérations ensemblistes en SQL,… ;</li><li>d''importer et d''exporter des données.</li></ul>' AS CLOB)
);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IIBD',1,'de développer et de gérer une base de données sur un système de gestion de bases de données
relationnelles et de manipuler des requêtes sous un langage tel que SQL,… dans des cas
simples.',60);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IIBD');

--IVTE
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IVTE',4,40,'VEILLE TECHNOLOGIQUE',' 7534 14 U32 D1 ',
cast('<ul class="prgm"><li>d’identifier les outils et les méthodologies de la veille technologique ;</li><li>de mettre en œuvre les principes-clés de la veille technologique ;</li><li>de définir les principales étapes d’un processus de veille ;</li><li>de mettre en place une cellule de veille ;</li><li>de résoudre les cas proposés et de rédiger un rapport reprenant :</li><li class="l2">des critiques pertinentes,</li><li class="l2">des solutions alternatives négociées en mode collaboratif,</li><li class="l2">des améliorations nécessaires à la réussite du projet de veille.</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IVTE',1,'de présenter devant le groupe-classe et via une technique de communication appropriée un rapport
circonstancié. ',100);
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IVTE');

--ISO2
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('ISO2',5,60,'STRUCTURE DES ORDINATEURS','7551 01 U32 D4',
CAST('<ul class="prgm"><li>s''approprier le sens du vocabulaire technique et l''utiliser d''une manière rigoureuse et appropriée ;</li><li>représenter l''information de manière numérique : systèmes décimal, binaire, hexadécimal, conversion de nombres, nombres entiers, nombres réels ;</li><li>identifier l''architecture matérielle et logicielle d''une configuration informatique donnée ;</li><li>identifier, expliciter le fonctionnement, différencier et choisir :</li><li class="l2">les éléments constitutifs du système central d''une configuration type en tenant compte de leur rôle, de leur fonctionnement et de leurs interactions, notamment :</li><li class="l3">le processeur : unité arithmétique et logique, décodage des instructions, bus interne, pipeline, processeurs parallèles,</li><li class="l3">la mémoire centrale : mémoire de programme et de données, mémoire cache, types de mémoires,</li><li class="l3">les bus : bus d''adresses, bus de données, bus de contrôle, bus interne,</li><li class="l3">les coupleurs : l''interface parallèle/série, le DMA, le temporisateur,</li><li class="l3">les coprocesseurs : mathématiques, de gestion de mémoire, graphiques, etc.,</li><li class="l3">les opérations de base du processeur ;</li><li class="l2">les périphériques courants, en tenant compte des évolution des besoins des utilisateurs :</li><li class="l3">les mémoires de masse : types, densité, formatage, temps d''accès, débit, etc.,</li><li class="l3">les imprimantes et traceurs,</li><li class="l3">les écrans, claviers, périphériques de pointage, etc.,</li><li class="l3">les liaisons : types de câbles, cartes et modems,</li><li class="l3">les différents types de réseaux informatiques ;</li><li>appréhender les éléments clés de sécurité d''un système informatique ainsi que le rôle de tout utilisateur et des informaticiens dans la chaîne de garantie de la sécurité.</li></ul>' AS CLOB)
);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('ISO2',1,'d''expliciter les éléments constitutifs d''une configuration donnée et son fonctionnement',30);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('ISO2',2,'de justifier le choix de la mise en œuvre technique et pratique',30);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','ISO2');

--XICP: Information et communication professionnelles
merge into TUE(CODE, ECTS, NB_PERIODES, NOM, REF, PRGM) values('XICP',3,40,'INFORMATION ET COMMUNICATION PROFESSIONNELLES',
    '035022U32D2',
    cast('<ul class="prgm"><li>de prendre des notes selon une combinaison de techniques appropriées ;</li><li class="l2">de mettre en œuvre les différentes méthodes de traitement de l''information :</li><li class="l2">repérer l''agencement logique de l''argumentation ,</li><li class="l2">identifier le but essentiel du message (convaincre, séduire, informer) ,</li><li class="l2">en évaluer le caractère objectif ou subjectif ;</li><li>de restructurer ses notes ;</li><li>de reformuler le message en l''adaptant au destinataire dans les perspectives suivantes :</li><li class="l2">communication externe (à large diffusion ou non) ,</li><li class="l2">communication interne (confidentielle ou non) ,</li><li class="l2">rapport d''information ou d''argumentation ,</li><li class="l2">transmission de données techniques, scientifiques, statistiques ou chiffrées ,</li><li class="l2">communication de dispositions réglementaires ou juridiques ,</li><li class="l2">élaboration d''un travail personnel ;</li><li>d''utiliser l''outil de communication approprié aux circonstances de production et de réception.</li></ul>' as CLOB)
	);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('XICP',1,'Produire un rapport de synthèse comprenant un résumé et un commentaire critique argumenté',50);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('XICP',2,'Élaborer et présenter un exposé oral simple',50);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','XICP');

-- ISE2 — Systèmes d'exploitation
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM)
values('ISE2',8,100,'SYSTEME D''EXPLOITATION','7552 03 U32 D4',
cast('<ul class="prgm"><li>de mobiliser les connaissances et méthodologies pour :</li><li>s''approprier le vocabulaire technique ;</li><li>appliquer une démarche de résolution de problème pour assurer :</li><li class="l2">installation et configuration,</li><li class="l2">configuration de la sécurité (droits d''accès, protocoles),</li><li class="l2">maintenance préventive et curative ;</li><li>participer à une configuration complète d''un système ;</li><li>mettre en oeuvre des comportements professionnels :</li><li class="l2">respect des standards,</li><li class="l2">utilisation des outils d''administration,</li><li class="l2">documentation cohérente ;</li><li>citer technologies et outils liés à la sécurité : hardening, baselining, listes blanches/noires, virtualisation, FDE, sauvegardes, etc. ;</li><li>de mobiliser les connaissances de manière opérationnelle pour :</li><li class="l2">déterminer besoins et choix techniques,</li><li class="l2">partitionner et formater des disques,</li><li class="l2">installer le système de fichiers,</li><li class="l2">gérer la mémoire,</li><li class="l2">gérer les E/S,</li><li class="l2">gérer les processus,</li><li class="l2">appliquer politique de sécurité,</li><li class="l2">gérer comptes utilisateurs,</li><li class="l2">appliquer procédures de maintenance ;</li><li>de programmer des procédures via langage de commande (shell) avec :</li><li class="l2">jokers, protections,</li><li class="l2">paramètres et variables,</li><li class="l2">formats d''affichage,</li><li class="l2">redirections, tubes,</li><li class="l2">structures de contrôle,</li><li class="l2">exécutions en tâche de fond,</li><li class="l2">sous-programmes et commentaires ;</li><li>d''adapter une installation existante ;</li><li>de remédier à des dysfonctionnements ;</li><li>d''appliquer une procédure de restauration ;</li><li>de communiquer à la maintenance les symptômes et interventions.</li></ul>' as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE)values ('ISE2',1,'rigueur et respect des spécificités du système d''exploitation',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE)values ('ISE2',2,'comportements professionnels',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE)values ('ISE2',3,'adéquation de la solution',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE)values ('ISE2',4,'respect du temps alloué',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE)values ('ISE2',5,'clarté et précision dans l''utilisation du vocabulaire technique',20);

--association UE Section
merge into TSEC_UE(FKSECTION,FKUE) values ('INFO','ISE2');

--INEB
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values(
  'INEB',
  5,
  80,
  'NOTIONS DE E-BUSINESS',
  '714506U32D1',
  cast('<ul class="prgm"><li>appréhender les concepts fondamentaux de l''e-business ;</li><li>analyser les modèles de l''e-business et leurs implications organisationnelles, logistiques et technologiques ;</li><li>élaborer un business plan complet pour un projet e-business ;</li><li>comprendre les bases juridiques liées aux droits de la propriété intellectuelle dans le contexte des TIC ;</li><li>analyser les fondements de la législation relative aux droits intellectuels ;</li><li>analyser les potentialités des solutions e-business en termes de création de valeur pour l''entreprise ;</li><li>identifier et comparer les modèles B2C, B2B et les plateformes d''intermédiation ;</li><li>exploiter des concepts novateurs dans le domaine de l''e-business ;</li><li>expliciter et appliquer les principes fondamentaux des droits applicables aux TIC ;</li><li>analyser des situations juridiques liées aux TIC et identifier les responsabilités impliquées.</li></ul>' as CLOB)
);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values
('INEB',1,'Élaborer un business plan complet pour un projet e-business en justifiant les choix : contexte, motivations, solutions logistiques, investissements informatiques, cahier des charges, méthodologie d''implantation.',40);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values
('INEB',2,'Analyser une situation juridique simple liée aux TIC, identifier les règles applicables, déterminer les responsabilités juridiques et en préciser les conséquences.',40);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values
('INEB',3,'Démontrer une argumentation précise et pertinente et utiliser correctement le vocabulaire technique du domaine.',20);

--association UE Section
merge into TSEC_UE(FKSECTION,FKUE) values ('INFO','INEB');

--IBR2
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IBR2',6,80,'BASES DES RESEAUX','298310U31D2',
cast('<ul class="prgm"><li>de décrire et d''utiliser des réseaux informatiques :</li><li class="l2">modèle OSI,</li><li class="l2">réseau Internet,</li><li class="l2">utilité et importance des réseaux de communication au sein des entreprises,</li><li class="l2">principaux périphériques mis en œuvre dans un interréseaux,</li><li class="l2">utilité et importance des protocoles utilisés,</li><li class="l2">structure des équipements réseaux,</li><li class="l2">concepts de la pile TCP/IP,</li><li class="l2">nombres binaires : conversion entre bases (10, 16 et 2),</li><li class="l2">adresses IPv4 et masques de sous-réseau,</li><li class="l2">terminologie des réseaux informatiques : protocoles réseaux, LAN, WAN, MAN, réseaux spécialisés, réseaux VPN,</li><li class="l2">importance de la bande passante son impact sur les applications (transport de son, de vidéo, etc.),</li><li class="l2">différentes topologies des réseaux informatiques : en bus, en étoile, en étoile étendue, en anneau, hiérarchique, … ;</li><li>de réaliser, de décrire et de caractériser des câbles informatiques :</li><li class="l2">grandeurs caractéristiques d''une sinusoïde : amplitude, période, fréquence, utilisation des décibels, …,</li><li class="l2">bande passante analogique et numérique,</li><li class="l2">câblage d''un LAN : analyse au niveau de la couche physique, médias Ethernet et utilisation des connecteurs, autres médias,…,</li><li class="l2">description des connections WAN (câble série, DSL, console, fibre,…) ;</li><li class="l2">de caractériser et d''utiliser la technologie Ethernet :</li><li class="l2">étude et comparaisons des technologies Ethernet (10Base T, architecture du 10Base T, 100Base FX, 1000Base T, multi-gigabits…),</li><li class="l2">caractéristiques de la norme Ethernet 802.3,</li><li class="l2">format d''une adresse MAC,</li><li class="l2">structure d''une trame Ethernet,</li><li class="l2">fonctionnement Ethernet : Média Access Control, Ethernet MAC, LLC, liaisons Half Duplex et Full Duplex, délai de propagation d''une trame Ethernet, types de collision d''une trame Ethernet, erreurs d''un trame Ethernet, auto-négociation d''une trame Ethernet, établissement d''une liaison Full et Half Duplex,</li><li class="l2">domaines de collision et domaines de broadcast,</li><li class="l2">unicast et broadcast en couche 2,</li><li class="l2">segmentation dans un réseau informatique,</li><li class="l2">évolutions possibles de l''Ethernet ;</li><li>de décrire et d''utiliser la commutation (switching) Ethernet :</li><li class="l2">rôle et utilité de la micro-segmentation,</li><li class="l2">latence,</li><li class="l2">modes de commutation (store and forward, cut through, fragment free,...) ;</li><li>de mettre en œuvre et d''utiliser des outils d''analyse du trafic et du fonctionnement de réseaux élémentaires (sniffers, icmp, traceroute …) ;</li><li>de décrire et de caractériser le protocole TCP/IP :</li><li class="l2">adressage IPv4 (types d''adresses publiques et privées, notion de classes),</li><li class="l2">routage avec translation d''adresse (utilisation d''adresses IPv4 privées,</li><li class="l2">notion de mise en place de sous-réseaux,</li><li class="l2">ARP, DHCP et problèmes de résolution d''adresses ;</li><li class="l2">notions d''adressage IPv6,</li><li>d''installer et de configurer un réseau connecté à Internet ;</li><li>de décrire et de caractériser des réseaux interconnectés :</li><li class="l2">protocoles routés et protocoles routables,</li><li class="l2">définition et mise en œuvre de sous-réseaux,</li><li class="l2">tables de routage statique,</li><li class="l2">métriques et algorithmes de routage,</li><li>de décrire et d''utiliser les couches transport et application :</li><li class="l2">sessions (établissement, maintien et fermeture),</li><li class="l2">principaux ports TCP et UDP,</li><li class="l2">principaux protocoles applicatifs (DNS, FTP, TFTP, HTTP, SMTP, SSH,…).</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IBR2',1,'de décrire les principales notions telles que le câblage, l''adressage IP, le modèle TCP/IP,…',40);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IBR2',2,'de décrire le fonctionnement d''un commutateur Ethernet et d''un routeur IPv4',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IBR2',3,'d''établir un plan d''adressage d''un réseau simple sous IPv4 avec un accès vers l''Internet',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IBR2',4,'de remédier à un dysfonctionnement simple (par ex : erreur d''adressage, câble débranché, …)',20);

--association UE Section
merge into TSEC_UE(FKSECTION,FKUE) values ('INFO','IBR2');

--IWPB
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IWPB',3,40,'WEB: PRINCIPES DE BASE','753429U32D1',
cast('<ul class="prgm"><li>face à une structure informatique opérationnelle connectée à Internet, disposant des logiciels appropriés et de la documentation nécessaire, en utilisant le vocabulaire technique et l’orthographe adéquat, ;</li><li class="l2">d’utiliser, d’installer et de configurer des navigateurs différents ;</li><li class="l2">d’utiliser les principaux services du Web ;</li><li class="l2">d’effectuer des recherches et des sélections pertinentes de l’information sur le Web en vue :</li><li class="l2">d’acquérir et d’utiliser la terminologie de base spécifique au domaine du Web,</li><li class="l2">d’expliciter la notion d’URL (structure, principe de redirection, etc.),</li><li class="l2">d’expliquer le processus de dépôt et de réservation des noms de domaine,</li><li class="l2">d’identifier les normes de standardisation du Web (ex : Consortium du W3C),</li><li class="l2">d’identifier les méthodes de « piratage » (virus, grabbing, phishing, hacking, etc.) ;</li><li class="l2">de créer et de structurer une page web (X) HTML en utilisant les balises spécifiques et leurs attributs, notamment :</li><li class="l2">les balises de structuration du document (doctype, en-têtes, etc.)</li><li class="l2">les balises de structuration et de hiérarchisation des contenus,</li><li class="l2">les balises de contenus textuels (paragraphes, titres, etc.), UE WEB :</li><li class="l2">les balises de contenus multimédia externes (images, vidéo, sons, etc.),</li><li class="l2">les balises de formulaires,</li><li class="l2">les hyperliens et objets interactifs,</li><li class="l2">etc. ;</li><li class="l2">de respecter la sémantique lors du choix des balises ;</li><li class="l2">de créer et de structurer une feuille de style CSS en déterminant les sélecteurs et en utilisant les propriétés (spécifications) adéquates ;</li><li class="l2">de réaliser la liaison entre les feuilles de styles et les pages web en utilisant les techniques et méthodologies les plus pertinentes ;</li><li class="l2">de réaliser, à l’aide de feuilles de style, des mises en page et des menus ;</li><li class="l2">de vérifier la compatibilité et l’apparence des pages web avec les principaux navigateurs et sur différents médias (smartphones, tablettes, etc.) ;</li><li class="l2">de transférer et de mettre à jour les fichiers nécessaires (HTML, CSS, média, etc.) sur un serveur ;</li><li class="l2">de recourir à bon escient à la documentation disponible.</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IWPB',1,'de réaliser des pages statiques, compatibles avec au minimum un navigateur récent du
marché',60);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IWPB',2,'de transférer et de tester ces pages statiques sur un serveur',40);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IWPB');

--IPW3
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values ('IPW3',10,100, 'PROJET DE DEVELOPPEMENT WEB', '753430U32D3',
cast('<p>face a un environnement matériel ou virtuel et au logiciel adéquats et face à une structure informatique opérationnelle connectée à Internet, disposant des logiciels appropriés et de la documentation nécessaire, en utilisant le vocabulaire technique et l''orthographe adéquate, et en respectant les normes et standards en vigueur, en appliquant le responsive design, Programmation côté client</p><ul class="prgm"><li>d’identifier, dans une page web, les éléments impliquant l’usage d’un script client ;</li><li>d’analyser un script client en termes de:</li><li class="l2">définition des variables et des objets,</li><li class="l2">structures conditionnelles et itératives,</li><li class="l2">fonctions et de procédures,</li><li class="l2">structures interactives (gestion des évènements,…),</li><li class="l2">etc. ;</li><li>d’exploiter un script client dans une page web ;</li><li>de modifier et de créer un script et de l’intégrer dans une page web ;</li><li>de décrire et de caractériser objets, propriétés et méthodes ;</li><li>de déterminer les événements auxquels les éléments de la page doivent réagir ;</li><li>de documenter sous formes de commentaires, de schémas, de dessins, etc., les éléments nécessaires à la résolution d’un problème posé (structures procédurales, interactives, animations, objets, etc.) ;</li><li>de mettre en œuvre la résolution d’un problème posé au moyen du langage client choisi ;</li><li>d’exploiter le côté orienté objet du langage choisi :</li><li class="l2">les classes prédéfinies et leurs composants (window, document, cookie, etc.),</li><li class="l2">la définition de classes et leur instanciation,</li><li class="l2">etc. ;</li><li>d’utiliser, dans le langage choisi, les variables, les structures conditionnelles, les structures itératives, les tableaux, l''affichage dans une page web, etc. ;</li><li>d’exploiter la notion d’expression régulière (validation de formulaires, etc.) ;</li><li>d’exploiter des données structurées en XML (Extensible Markup Langage), en JSON (JavaScript Object Notation), etc., contenues dans un fichier externe ;</li><li>de décrire et de mettre en œuvre des technologies entrant dans le développement d’applications web dynamiques et animées tel que AJAX (Asynchronous Javascript and XML), ... ;</li><li>de choisir et d’exploiter une bibliothèque tierce, en vue du développement de scripts spécifiques pour RIA (interfaces riches), transmissions asynchrones, ... ;</li><li>d’identifier et de mettre en œuvre la solution cloud appropriée ;</li><li>d’intégrer les solutions DevOps :</li><li class="l2">Logiciels de gestion de version (Git, …),</li><li class="l2">Intégration continue,</li><li class="l2">Déploiement continu ;</li><li>d’identifier des erreurs de programmation au moyen d’outils ou de techniques de débogage et d’y apporter une solution pertinente ;</li><li>d’implémenter, d’utiliser et de sécuriser une API.</li></ul><p><strong>Programmation côté serveur</strong></p><ul class="prgm"><li>d’identifier différents langages utilisés pour la programmation côté serveur ;</li><li>d’installer les services nécessaires à l’exécution de scripts côté serveur ;</li><li>d’analyser un script serveur en termes de:</li><li class="l2">définition des variables,</li><li class="l2">structures conditionnelles et itératives,</li><li class="l2">fonctions et de procédures,</li><li class="l2">etc. ;</li><li>d’exploiter le modèle MVC (Model View Controller) ;</li><li>d’exploiter un script serveur dans une page web ;</li><li>d’utiliser, dans le langage choisi, les variables de programmation et d’environnement (session, application, cookies, etc.) ;</li><li>de transférer des données entre pages et scripts (méthodes GET et POST, etc.) ;</li><li>de documenter sous formes de commentaires, de schémas, de dessins, etc. les éléments nécessaires à la mise en œuvre d’une application dynamique (structure procédurale, transfert et conservation des données, interaction avec des données externes, etc.) ;</li><li>de citer les notions, technologies et outils liés à la sécurité de l''information ainsi que les conséquences de leurs usages (prérequis, coûts, organisation) : vulnérabilités courantes, OWASP, dépassement de tampon, injection, assainissement d''entrée, principes fondamentaux de développement web sécurisé, WAF, surveillance ("monitoring") ... ;</li><li>de mettre en œuvre une application web et de la tester (validation des données et validation fonctionnelle) ;</li><li>d’exploiter le système de gestion de fichiers du serveur (se déplacer dans l’arborescence, créer et modifier un fichier, créer un dossier et en gérer les droits d’accès fonctionnels (en ce compris dans l’application) …) ;</li><li>d’identifier et de mettre en œuvre la solution cloud appropriée ;</li><li>d’intégrer les solutions DevOps :</li><li class="l2">Logiciels de gestion de version (Git, …),</li><li class="l2">Intégration continue,</li><li class="l2">Déploiement continu ;</li><li>d’identifier des erreurs de programmation au moyen d’outils ou de techniques de débogage et d’y apporter une solution pertinente ;</li><li>d’implémenter, d’utiliser et de sécuriser une API.</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPW3',1,'créer et d’exploiter des scripts clients basés sur des classes prédéfinies',10);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPW3',2,'créer et d’exploiter ses propres classes',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPW3',3,'créer et d’exploiter des scripts basés sur une bibliothèque tierce',10);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPW3',4,'envoyer des informations venant du client vers le serveur et de les traiter',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPW3',5,'générer un ensemble de pages web contenant un système de navigation et un contenu
dynamiques intégrant formulaires et résultats',20);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPW3',6,'implémenter, d’utiliser et de sécuriser une API',20);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IPW3');

--IPC2
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IPC2',10,100,'PROJET D''ANALYSE ET DE CONCEPTION','7512 11 U32 D2',
cast('<ul class="prgm"><li>de préciser les spécifications du problème proposé afin d''établir un cahier des charges ;</li><li>de mettre en œuvre une méthodologie de résolution de problème au travers d''études de cas (observation, résolution, justification, expérimentation, validation) ;</li><li>de recueillir, avec les différentes parties prenantes, les informations nécessaires à la compréhension du problème et de son contexte (structure de l''organisation, contraintes, etc.) en appliquant des techniques de communication adaptées ;</li><li>de participer à l''étude, la conception, la modélisation et la validation des informations recueillies et des scénarios de solution grâce aux diagrammes standardisés et aux tables de décision ;</li><li>de participer à l''étude, la conception, la modélisation et la validation de solutions techniques en vue de la réalisation et de l''implantation du projet (traduction en architecture logicielle selon des schémas actuels tels que Cloud, Saas, etc.), en élaborant des scénarios de tests et des contraintes de sécurité (rôles) de niveau analyse ;</li><li>de mettre en œuvre les ressources appropriées en vue de constituer la documentation adéquate à chaque étape du projet ;</li><li>de planifier et contrôler l''état d''avancement d''un projet grâce à une méthode de suivi de projet standardisée ;</li><li>de recourir à bon escient à la documentation disponible.</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPC2',1,'structurer et modéliser les besoins du client selon une démarche adaptée',35);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPC2',2,'construire et modéliser un scénario de solution',30);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPC2',3,'traduire en architecture logicielle la solution proposée',25);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPC2',4,'justifier le suivi du projet',10);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IPC2');

--IPL3
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IPL3',9,100,'PRODUITS LOGICIELS DE GESTION INTEGRES','711106U32D3',
cast('<p><strong>En Comptabilité :</strong></p><ul class="prgm"><li>de percevoir le rôle et l''organisation du système d''information comptable dans l''entreprise;</li><li>d''identifier les principaux documents commerciaux usuels servant de support au système d''information comptable et financière ;</li><li>d''acquérir les mécanismes de base de la comptabilité en partie double et des comptes annuels;</li><li>d''appliquer aux opérations courantes le Plan Comptable Minimum Normalisé (P.C.M.N.) et les techniques comptables usuelles pour tenir les journaux et les comptes de gestion permettant de dresser les comptes annuels;</li><li>d''établir les liens fondamentaux entre la comptabilité générale et la comptabilité analytique.</li></ul><p><strong>En Laboratoire de logiciels de gestion intégrés :</strong></p><ul class="prgm"><li>d''appréhender l''environnement des logiciels de gestion intégrés;</li><li>d''analyser les différentes fonctionnalités de ces logiciels et leurs potentialités;</li><li>de mettre en œuvre des procédures de gestion liées aux logiciels intégrés :</li><li class="l2">le concept d''autorisation,</li><li class="l2">les flux virtuels de l''entreprise,</li><li class="l2">l''interrogation de la base de données,</li><li class="l2">le reporting,</li><li class="l2">la configuration et la gestion des données;</li><li>de réaliser des travaux pratiques simples en matière comptable (enregistrement des pièces, éditions des journaux et des comptes, etc.) et de gestion (approvisionnement, stocks, clients, fournisseurs, etc.).</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPL3',1,'appliquer des procédures de gestion liées aux logiciels intégrés',50);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPL3',2,'réaliser des travaux simples en matière comptable et de gestion',50);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IPL3');

--4IMA2
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IMA2',4,60,'PROJET D’INTEGRATION DE DEVELOPPEMENT','0121 02 U32 D4',
cast('<ul class="prgm"><li>en Mathématiques appliquées à l’informatique</li><li>de mettre en œuvre une démarche de résolution de problèmes en utilisant les 		ressources :</li><li class="l2">de l’algèbre linéaire (calcul matriciel) appliquée à la représentation et la 	manipulation de tableaux (dimensions des vecteurs et des matrices, opérations sur 	les vecteurs et sur les matrices, propriétés de ces opérations),</li><li class="l2">du calcul itératif</li><li class="l2">de l’étude des graphes (sortes de graphes ; degrés, chemins, circuits et cycles ; 	représentation matricielle ; graphes connexes, arbre, racine, arbres binaires, 	problèmes d’ordonnancement),</li><li class="l2">d’éléments de la théorie des ensembles en vue de leur application (représentation 	des ensembles, opérations sur les ensembles, sous-ensembles, relations, 	représentation graphique)</li><li class="l2">de l’algèbre relationnelle (notion de table, de relations, de requêtes)</li><li class="l2">d’éléments de logique mathématique (proposition, conjonction, disjonction, 	négation, tables de vérité, lois de de Morgan, raisonnement et implication logique) ;</li><li>de citer les notions, technologies et outils liés à la sécurité de l’information : cryptographie, cryptanalyse, confidentialité, intégrité, hachage, sel, chiffrement symétrique et asymétrique, certificat, RSA, AES, stéganographie, PGP, SSH, TLS, PKI, espace de clés .</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IMA2',1,'de résoudre un problème faisant appel à l’algèbre linéaire, au calcul itératif, à l’étude des
graphes, à la théorie des ensembles, à l’algèbre relationnelle ou à la logique mathématique',50);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IMA2',2,'de présenter son cahier des charges et de défendre ses solutions',30);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IMA2',3,'de présenter son cahier des charges et de défendre ses solutions.',20);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IMA2');

--IPDB
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('IPDB',8,80,'PROJET DE DEVELOPPEMENT SGBD','754403U32D2',
cast('<ul class="prgm"><li>en disposant d’une station informatique opérationnelle équipée d’un logiciel « Bases de données », d’un outil de développement, en utilisant les dernières techniques d’accès aux bases de données,</li><li>de se connecter sur une base de données par programmation ;</li><li>d’ajouter, de modifier, de supprimer des données par programmation ;</li><li>de vérifier l’intégrité des données par programmation ;</li><li>de récupérer et de gérer les erreurs générées par la base de données par programmation ;</li><li>d’implémenter une interface visuelle qui permet la gestion et la validation des données ;</li><li>de programmer des transactions ;</li><li>de découper la programmation en différentes couches (Data Access Layer, Business Object, Business Layer…) ;</li><li>de débugger la programmation (breakpoint, Statut des variables, Step by step…).</li><li>de s’assurer de la qualité des données d’un point de vue technique (cohérence,normalisation, complétion, actualisation, …).</li><li>en disposant d’une station informatique opérationnelle équipée d’un logiciel « Bases de données », d’un outil de développement et sur base d’un cahier des charges fourni par le chargé de cours, en utilisant les dernières techniques d’accès aux bases de données,</li><li>d’implémenter la base de données et l’intégrité des données ;</li><li>d’implémenter et de débugger une interface visuelle qui gère et valide les données et leur intégrité.</li><li>d’identifier et de mettre en œuvre une solution cloud appropriée ;</li><li>d’intégrer les solutions DevOps appropriées aux projets SGBD</li><li class="l2">Logiciels de gestion de version (Git, …),</li><li class="l2">Intégration continue,</li><li class="l2">Déploiement continu.</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPDB',1,'d’élaborer et de défendre un dossier technique reprenant :
*le schéma de la base de données,*l’expression des contraintes en langage usuel,*la documentation du code et la gestion des erreurs ; ',50);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPDB',2,'d’implémenter une base de données et l’intégrité des données;',25);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('IPDB',3,'de programmer, de tester et de défendre la programmation de l’interface visuelle qui
permet la gestion des données.',25);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','IPDB');

--ITG2
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('ITG2',3,40,'TECHNIQUES DE GESTION DE PROJET','7502 05 U32 D2',
cast('<p>Au travers d''études de cas, l''étudiant apprend à appréhender le concept de projet et sa structure, à caractériser le cycle de vie d''un projet et les spécificités des projets informatiques, à décrire les différentes phases, à appliquer les principaux modèles de développement, à estimer un projet en termes de durée, planification et coûts, et à utiliser des techniques de supervision et de suivi de projet.</p>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('ITG2',1,'Appliquer les méthodes et outils de gestion de projet afin de formaliser et de finaliser un projet à partir d''un scénario donné.',60);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('ITG2',2,'Rédiger un rapport argumenté décrivant et analysant les phases de construction du projet et en estimant les délais de réalisation et les coûts.',40);
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','ITG2');

--XSTA
merge into TUE(CODE,ECTS,NB_PERIODES,NOM,REF,PRGM) values('XSTA',3,40,'ELEMENTS DE STATISTIQUE','013203U32D2',
cast('<ul class="prgm"><li>de s''approprier les concepts de base de la statistique et de la probabilité ;</li><li>de mettre en œuvre une démarche de résolution de problèmes en utilisant les ressources :</li><li class="l2">de la statistique descriptive univariée :</li><li class="l3">Analyse du problème posé,</li><li class="l3">Traitement approprié d''un ensemble de données sous forme de tableaux,</li><li class="l3">Traitement approprié d''un ensemble de données sous forme de graphiques,</li><li class="l3">Résumé des données au moyen des mesures de position, des mesures de dispersion et des mesures de forme,</li><li class="l3">Interprétation des résultats obtenus,</li><li class="l2">de la statistique descriptive bivariée :</li><li class="l3">Représentation graphique (nuage de points et droite de régression),</li><li class="l3">Technique d''ajustement linéaire (méthode des moindres carrés et corrélation),</li><li class="l3">Interprétation des résultats obtenus et prédiction,</li><li class="l3">Elargissement à un ajustement non linéaire,</li><li class="l2">de la probabilité :</li><li class="l3">Calculs de probabilités simples,</li><li class="l3">Détermination de la loi de probabilité d''une variable aléatoire (+ espérance),</li><li class="l3">Identification des lois de probabilités usuelles (loi binomiale, loi de Poisson, loi normale, …),</li><li class="l3">Utilisation des tables de ces lois de probabilité ;</li></ul><p><strong>en laboratoire de logiciel appliqué à la statistique :</strong></p><ul class="prgm"><li>en statistique descriptive univariée :</li><li class="l2">de réaliser le traitement des données ;</li><li class="l2">de les représenter graphiquement ;</li><li class="l2">de calculer les mesures de position, de dispersion et de forme ;</li><li>en statistique descriptive bivariée :</li><li class="l2">de représenter graphiquement le nuage de points et la droite de régression ;</li><li class="l2">de calculer le coefficient de corrélation et la droite de régression.</li></ul>'as CLOB));
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('XSTA',1,'d''expliciter les concepts et les techniques à appliquer en utilisant le vocabulaire d''une manière adéquate ;',30);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('XSTA',2,'d''appliquer les techniques, les démarches appropriées pour assurer le traitement des données ;',40);
merge into TACQUIS(FKUE,NUM,ACQUIS,POURCENTAGE) values ('XSTA',3,'de présenter les résultats en utilisant les ressources du logiciel disponible (tableaux, graphiques, …) et de les interpréter.',30);

--association UE Section
merge into TSEC_UE (FKSECTION,FKUE) values ('INFO','XSTA');
merge into TSEC_UE (FKSECTION,FKUE) values ('SECR','XSTA');
merge into TSEC_UE (FKSECTION,FKUE) values ('MARK','XSTA');

